item.content:encoded:
/* Hide first featured image */
.post .featured-image {
    display: none;
}

/* Resize featured image if keeping one */
.inside-article .entry-content .wp-block-post-featured-image img {
	max-height: 300px;
	object-fit: cover;
	margin-bottom: 20px;
}

.inside-article .wp-block-image {
	text-align: center;
	margin-bottom: 20px;
}

